mapper.select:
SELECT b.id, b.name, b.author, b.price, b.publisher, b.isbn, b.category_id, b.total_stock, b.stock, b.publish_date, b.description, b.create_time, c.name AS category_name FROM book b LEFT JOIN category c ON b.category_id = c.id
AND b.name LIKE CONCAT('%', #{name}, '%')
AND b.author LIKE CONCAT('%', #{author}, '%')
AND b.publisher LIKE CONCAT('%', #{publisher}, '%')
AND b.category_id = #{categoryId}
ORDER BY b.id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE book
name = #{name}, author = #{author}, price = #{price}, publisher = #{publisher}, isbn = #{isbn}, category_id = #{categoryId}, total_stock = #{totalStock}, publish_date = #{publishDate}, description = #{description},
WHERE id = #{id}
